div.ul:

Employee: ${object.employee_id.name}

Job Position: ${object.job_id.name or 'N/A'}

Department: ${object.department_id.name or 'N/A'}
                    % if object.date_end:

Contract End Date: ${object.date_end.strftime('%d-%b-%Y')}
                    % endif
                    % if object.document_expiry_date:

Document Expiry Date: ${object.document_expiry_date.strftime('%d-%b-%Y')}

Document Type: ${object.document_type_id.name or 'N/A'}
                    % endif
                    % if object.passport_expiry_date:

Passport Expiry Date: ${object.passport_expiry_date.strftime('%d-%b-%Y')}
                    % endif
